{"code": "import json

# Access the business data from the last query
business_data = var_functions.query_db_44

# Process the data manually
states = {
    'CA': {'name': 'California', 'reviews': 0},
    'MO': {'name': 'Missouri', 'reviews': 0},
    'ID': {'name': 'Idaho', 'reviews': 0},
    'FL': {'name': 'Florida', 'reviews': 0},
    'IN': {'name': 'Indiana', 'reviews': 0}
}

for business in business_data:
    desc = business.get('description', '')
    review_count = int(business.get('review_count', 0))

    for code, info in states.items():
        if f', {code},' in desc or f', {code}' in desc:
            info['reviews'] += review_count
            break

# Find state with most reviews
max_reviews = 0
top_state = ''

for code, info in states.items():
    if info['reviews'] > max_reviews:
        max_reviews = info['reviews']
        top_state = info['name']

result = {
    'top_state': top_state,
    'total_reviews': max_reviews,
    'state_details': states
}

print('__RESULT__:')
print(json.dumps(result))"}

